// UnknownReasonEqOverrides carries optional per-variant hooks for UnknownReasonEqualWith.
// A hook returning handled=false falls through to the derived comparison.
type UnknownReasonEqOverrides struct {
	UnsupportedTheory func(x, y UnsupportedTheory) (eq, handled bool)
	ResourceLimit     func(x, y ResourceLimit) (eq, handled bool)
	Canceled          func(x, y Canceled) (eq, handled bool)
}

// UnknownReasonEqualWith reports structural equality of a and b under ov.
func UnknownReasonEqualWith(a, b UnknownReason, ov UnknownReasonEqOverrides) bool {
	if a == nil || b == nil {
		return a == nil && b == nil
	}
	switch x := any(a).(type) {
	case UnsupportedTheory:
		y, ok := any(b).(UnsupportedTheory)
		if !ok {
			return false
		}
		if ov.UnsupportedTheory != nil {
			if eq, handled := ov.UnsupportedTheory(x, y); handled {
				return eq
			}
		}
		if x.Name != y.Name {
			return false
		}
		return true
	case ResourceLimit:
		y, ok := any(b).(ResourceLimit)
		if !ok {
			return false
		}
		if ov.ResourceLimit != nil {
			if eq, handled := ov.ResourceLimit(x, y); handled {
				return eq
			}
		}
		if x.Limit != y.Limit {
			return false
		}
		return true
	case Canceled:
		y, ok := any(b).(Canceled)
		if !ok {
			return false
		}
		if ov.Canceled != nil {
			if eq, handled := ov.Canceled(x, y); handled {
				return eq
			}
		}
		_ = y
		return true
	}
	return false
}

// UnknownReasonEqual reports structural equality of a and b.
func UnknownReasonEqual(a, b UnknownReason) bool {
	return UnknownReasonEqualWith(a, b, UnknownReasonEqOverrides{})
}

